10	extension Float {
11	    func formattedValue(trimZeroes: Bool = false) -> String {
12	        switch self {
13	        case 0..<10:
14	            return trimZeroes
15	                ? formatted(.number.precision(.fractionLength(0...2)))
16	                : String.localizedStringWithFormat("%.2f", self)
17	        case 10..<100:
18	            return trimZeroes
19	                ? formatted(.number.precision(.fractionLength(0...1)))
20	                : String.localizedStringWithFormat("%.1f", self)
21	        case 100..<1000:
22	            return "\(Int(self))"
23	        case 1000..<10_000:
24	            return String(localized: .Localization.formattedThousandDouble(Double(floor(self / 1000 * 10) / 10)))
25	        case 10_000..<1_000_000:
26	            return String(localized: .Localization.formattedThousandInt(Int(self / 1000)))
27	        case 1_000_000...Float.infinity:
28	            return String(localized: .Localization.formattedMillion(Double(floor(self / 1_000_000 * 10) / 10)))
29	        default:
30	            return "--"
31	        }
32	    }
33	}
